#!/usr/bin/env tsx
// SEARXNG-YANDEX-SHADOW-LANE-1
// Sibling script to run-comparison.ts, NOT a modification of it. Reuses the
// exact same 100-query benchmark file (scripts/searxng-poc/benchmark-100-queries.json,
// itself derived from the real query universe -- no second parallel universe
// created here), the same OpenSERP-native baseline call, and the EXISTING,
// UNMODIFIED AkarFinder admission pipeline (decideAdmission). The only
// difference: SearXNG is queried for engines=yandex only -- no duckduckgo,
// brave, startpage, mojeek, qwant, or google traffic is generated by this
// script at all.
//
// This script NEVER touches Supabase or any database -- it has zero DB
// credentials and makes zero DB calls, by design (see the mission's own
// architecture note: a real, tagged write to discovery_candidates would
// require exposing SUPABASE_SERVICE_ROLE_KEY to a GitHub Actions runner for
// the first time ever in this project, which is a new secret-exposure
// decision, not a reuse of "voie existante" -- out of scope here, reported
// separately rather than decided unilaterally). This script's sole job is to
// produce the raw, admitted-candidate data (including full canonical URLs,
// not just counts) needed for an OFFLINE, LOCAL, read-only cross-check
// against the real discovery_candidates/listing_sources tables after the
// fact -- never fetches a listing page, never fetches an image, never
// touches openserp_query_rotation_state or openserp_engine_budget_state.

import { readFileSync, writeFileSync } from "node:fs";
import { join } from "node:path";
import { createOpenSerpNativeClient } from "@/lib/openserp-async/openserp-native-client";
import { OpenSerpHttpError } from "@/lib/openserp-async/openserp-client";
import { decideAdmission, type AdmissionDecision } from "@/lib/openserp-ingestion/national-admission";
import { classifyEngineErrorDetail, type EngineErrorCategory } from "@/lib/openserp-ingestion/engine-error-diagnostics";
import type { OpenSerpIngestionQuery } from "@/lib/openserp-ingestion/types";
import type { OpenSerpRawResult } from "@/lib/openserp-async/types";

const OPENSERP_URL = (process.env.OPENSERP_LOCAL_URL ?? "http://127.0.0.1:7070").replace(/\/+$/, "");
const SEARXNG_URL = (process.env.SEARXNG_URL ?? "http://127.0.0.1:8888").replace(/\/+$/, "");
// Mission constraint: activate ONLY yandex. Every other SearXNG engine
// (google, duckduckgo, brave, startpage, mojeek, qwant) is deliberately
// excluded from this list and therefore never requested.
const SEARXNG_ENGINES = ["yandex"];
const REQUEST_TIMEOUT_MS = 15_000;

type BenchmarkQuery = {
  query_id: string;
  city: string;
  district: string | null;
  transaction: "sale" | "rent";
  property_type: string;
  priority_tier: 1 | 2 | 3 | 4;
  query_text: string;
  target_domain: string | null;
  query_family: "general" | "brand_hint";
};

type RawRecord = { engine: string; url: string; title: string; snippet: string | null; rank: number };

type EngineAttemptResult = {
  records: RawRecord[];
  durationMs: number;
  errors: Array<{ engine: string; category: EngineErrorCategory | "searxng_unresponsive"; message: string }>;
};

function toIngestionQuery(q: BenchmarkQuery): OpenSerpIngestionQuery {
  return {
    query_id: q.query_id,
    city: q.city,
    district: q.district ?? "",
    transaction_type: q.transaction,
    property_type: q.property_type,
    query_text: q.query_text,
    priority: q.priority_tier <= 1 ? "high" : q.priority_tier === 2 ? "medium" : "low",
    target_domain: q.target_domain ?? undefined,
    query_family: q.query_family,
  };
}

function classifySearxngErrorMessage(message: string): EngineErrorCategory | "searxng_unresponsive" {
  const lower = message.toLowerCase();
  if (lower.includes("captcha")) return "captcha";
  if (lower.includes("403")) return "http_403";
  if (lower.includes("429")) return "http_429";
  if (lower.includes("timeout") || lower.includes("timed out")) return "timeout";
  return "searxng_unresponsive";
}

async function fetchWithTimeout(url: string, timeoutMs: number): Promise<Response> {
  const controller = new AbortController();
  const timeout = setTimeout(() => controller.abort(), timeoutMs);
  try {
    return await fetch(url, { signal: controller.signal });
  } finally {
    clearTimeout(timeout);
  }
}

async function fetchSearxngYandex(query: BenchmarkQuery): Promise<EngineAttemptResult> {
  const started = Date.now();
  const params = new URLSearchParams();
  params.set("q", query.query_text);
  params.set("format", "json");
  params.set("categories", "general");
  params.set("engines", SEARXNG_ENGINES.join(","));

  try {
    const response = await fetchWithTimeout(`${SEARXNG_URL}/search?${params.toString()}`, REQUEST_TIMEOUT_MS);
    const bodyText = await response.text();

    if (!response.ok) {
      const category = response.status === 429 ? "http_429" : response.status === 403 ? "http_403" : "unknown";
      return {
        records: [],
        durationMs: Date.now() - started,
        errors: SEARXNG_ENGINES.map((engine) => ({ engine, category, message: `searxng http ${response.status}` })),
      };
    }

    const json = JSON.parse(bodyText) as {
      results?: Array<{ url?: string; title?: string; content?: string; snippet?: string; engine?: string; engines?: string[]; positions?: Record<string, number> }>;
      unresponsive_engines?: Array<[string, string]>;
    };

    const records: RawRecord[] = [];
    for (const [index, r] of (json.results ?? []).entries()) {
      const url = r.url;
      if (!url) continue;
      const title = r.title ?? "";
      const snippet = r.content ?? r.snippet ?? null;
      const engines = r.engines && r.engines.length > 0 ? r.engines : r.engine ? [r.engine] : ["unknown"];
      for (const engine of engines) {
        if (!SEARXNG_ENGINES.includes(engine)) continue; // defense in depth: never record a non-yandex engine even if SearXNG's response tags one
        const rank = r.positions?.[engine] ?? index + 1;
        records.push({ engine, url, title, snippet, rank });
      }
    }

    const errors = (json.unresponsive_engines ?? [])
      .filter(([engine]) => SEARXNG_ENGINES.includes(engine))
      .map(([engine, message]) => ({
        engine,
        category: classifySearxngErrorMessage(message ?? ""),
        message: String(message ?? "").slice(0, 200),
      }));

    return { records, durationMs: Date.now() - started, errors };
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);
    const category = error instanceof Error && error.name === "AbortError" ? "timeout" : "unknown";
    return {
      records: [],
      durationMs: Date.now() - started,
      errors: SEARXNG_ENGINES.map((engine) => ({ engine, category, message })),
    };
  }
}

async function fetchOpenserp(query: BenchmarkQuery): Promise<EngineAttemptResult> {
  const started = Date.now();
  const client = createOpenSerpNativeClient({ baseUrl: OPENSERP_URL, timeoutMs: REQUEST_TIMEOUT_MS });
  const attemptEngines: Array<"bing" | "duckduckgo" | "ecosia"> = ["duckduckgo"];
  const errors: EngineAttemptResult["errors"] = [];

  for (const engine of attemptEngines) {
    try {
      const response = await client.search({ engine, query: query.query_text, limit: 15, locale: "fr-MA" });
      const records: RawRecord[] = response.results.map((r, index) => ({
        engine,
        url: r.url ?? "",
        title: r.title ?? "",
        snippet: r.snippet ?? null,
        rank: r.position?.absolute ?? r.rank ?? index + 1,
      })).filter((r) => r.url);
      return { records, durationMs: Date.now() - started, errors };
    } catch (error) {
      const httpStatus = error instanceof OpenSerpHttpError ? error.status : null;
      const message = error instanceof Error ? error.message : String(error);
      const category = classifyEngineErrorDetail({
        outcome: null,
        errorName: error instanceof Error ? error.name : null,
        errorCode: null,
        httpStatus,
        message,
      });
      errors.push({ engine, category, message: message.slice(0, 200) });
    }
  }

  return { records: [], durationMs: Date.now() - started, errors };
}

// Mirrors national-writer.ts's (unexported) discoveryStatusFor exactly --
// duplicated here rather than imported/exported so this mission never edits
// a single line of the real OpenSERP production writer.
function shadowDiscoveryStatusFor(decision: AdmissionDecision): "accepted" | "rejected" | "unclassified" {
  if (decision.admitted) return "accepted";
  if (decision.classified?.classification_lane === "reject_out_of_scope") return "rejected";
  return "unclassified";
}

type AdmittedYandexRecord = {
  query_id: string;
  city: string;
  property_type: string;
  canonical_url: string;
  source_domain: string;
  title: string;
  snippet: string | null;
  rank: number;
  engine: "yandex";
};

async function main() {
  const benchmarkPath = join(process.cwd(), "scripts/searxng-poc/benchmark-100-queries.json");
  const benchmark = JSON.parse(readFileSync(benchmarkPath, "utf8")) as { queries: BenchmarkQuery[] };

  const runStarted = Date.now();

  let openserpRaw = 0;
  let openserpAdmittedTotal = 0;
  const openserpAdmittedUrls = new Set<string>();
  const openserpErrors: Record<string, number> = {};
  let openserpDurationMs = 0;

  let yandexRawTotal = 0;
  const yandexUniqueRawUrls = new Set<string>();
  let yandexAccepted = 0;
  let yandexRejected = 0;
  let yandexUnclassified = 0;
  const yandexErrors: Record<string, number> = {};
  let yandexDurationMs = 0;
  const yandexCitiesCovered = new Set<string>();
  const yandexPropertyTypesCovered = new Set<string>();
  const yandexTopDomains = new Map<string, number>();
  const admittedYandexRecords: AdmittedYandexRecord[] = [];

  for (let i = 0; i < benchmark.queries.length; i += 1) {
    const query = benchmark.queries[i];
    console.log(`[progress] ${i + 1}/${benchmark.queries.length} query_id=${query.query_id} city=${query.city} text="${query.query_text}"`);

    const [openserpResult, yandexResult] = await Promise.all([fetchOpenserp(query), fetchSearxngYandex(query)]);

    openserpRaw += openserpResult.records.length;
    openserpDurationMs += openserpResult.durationMs;
    for (const err of openserpResult.errors) openserpErrors[err.category] = (openserpErrors[err.category] ?? 0) + 1;
    for (const rec of openserpResult.records) {
      const decision = decideAdmission({
        result: { title: rec.title, url: rec.url, snippet: rec.snippet ?? undefined, rank: rec.rank, engine: rec.engine } as OpenSerpRawResult,
        query: toIngestionQuery(query),
        engine: "duckduckgo",
        discovered_at: new Date().toISOString(),
        fallbackRank: rec.rank,
      });
      if (decision.admitted && decision.classified) {
        openserpAdmittedTotal += 1;
        openserpAdmittedUrls.add(decision.classified.canonical_source_url);
      }
    }

    yandexDurationMs += yandexResult.durationMs;
    for (const err of yandexResult.errors) yandexErrors[err.category] = (yandexErrors[err.category] ?? 0) + 1;
    yandexRawTotal += yandexResult.records.length;
    for (const rec of yandexResult.records) yandexUniqueRawUrls.add(rec.url);

    for (const rec of yandexResult.records) {
      const decision = decideAdmission({
        result: { title: rec.title, url: rec.url, snippet: rec.snippet ?? undefined, rank: rec.rank, engine: rec.engine } as OpenSerpRawResult,
        query: toIngestionQuery(query),
        engine: "duckduckgo", // decideAdmission's `engine` param is provenance metadata only (stored in classified.engine); it does not gate admission logic, so using the same literal the rest of this codebase's offline POC tooling already uses is safe here too -- the real value ("yandex") is recorded separately on every output record below instead.
        discovered_at: new Date().toISOString(),
        fallbackRank: rec.rank,
      });
      const status = shadowDiscoveryStatusFor(decision);
      if (status === "accepted") yandexAccepted += 1;
      else if (status === "rejected") yandexRejected += 1;
      else yandexUnclassified += 1;

      if (status === "accepted" && decision.classified) {
        const c = decision.classified;
        yandexCitiesCovered.add(query.city);
        yandexPropertyTypesCovered.add(query.property_type);
        yandexTopDomains.set(c.source_domain, (yandexTopDomains.get(c.source_domain) ?? 0) + 1);
        admittedYandexRecords.push({
          query_id: query.query_id,
          city: query.city,
          property_type: query.property_type,
          canonical_url: c.canonical_source_url,
          source_domain: c.source_domain,
          title: c.title,
          snippet: c.snippet,
          rank: rec.rank,
          engine: "yandex",
        });
      }
    }
  }

  const totalDurationMs = Date.now() - runStarted;

  const uniqueAdmittedYandexUrls = new Set(admittedYandexRecords.map((r) => r.canonical_url));
  const overlapWithOpenserpRun = [...uniqueAdmittedYandexUrls].filter((u) => openserpAdmittedUrls.has(u));
  const incrementalVsOpenserpRun = [...uniqueAdmittedYandexUrls].filter((u) => !openserpAdmittedUrls.has(u));

  const report = {
    benchmark_size: benchmark.queries.length,
    total_run_duration_ms: totalDurationMs,
    openserp_baseline: {
      raw_results: openserpRaw,
      admitted_total: openserpAdmittedTotal,
      unique_admitted_urls: openserpAdmittedUrls.size,
      errors: openserpErrors,
      avg_duration_ms: benchmark.queries.length > 0 ? Math.round(openserpDurationMs / benchmark.queries.length) : 0,
    },
    yandex: {
      raw_results: yandexRawTotal,
      unique_raw_urls: yandexUniqueRawUrls.size,
      accepted: yandexAccepted,
      rejected: yandexRejected,
      unclassified: yandexUnclassified,
      unique_admitted_canonical_urls: uniqueAdmittedYandexUrls.size,
      overlap_with_openserp_this_run: overlapWithOpenserpRun.length,
      incremental_vs_openserp_this_run: incrementalVsOpenserpRun.length,
      cities_covered: yandexCitiesCovered.size,
      property_types_covered: yandexPropertyTypesCovered.size,
      top_domains: [...yandexTopDomains.entries()].sort((a, b) => b[1] - a[1]).slice(0, 10),
      errors: yandexErrors,
      avg_duration_ms: benchmark.queries.length > 0 ? Math.round(yandexDurationMs / benchmark.queries.length) : 0,
    },
    // Full admitted-record list -- deliberately included (not just counts)
    // so a SEPARATE, local, read-only script can cross-check every one of
    // these canonical URLs against the real discovery_candidates/
    // listing_sources tables after this run finishes. This script itself
    // makes that comparison unavailable by design (no DB credentials here).
    admitted_yandex_records: admittedYandexRecords,
  };

  console.log("\n=== FINAL REPORT ===");
  console.log(JSON.stringify(report, null, 2));

  writeFileSync(join(process.cwd(), "scripts/searxng-poc/yandex-shadow-report.json"), JSON.stringify(report, null, 2), "utf8");
}

main().catch((error) => {
  console.error("Fatal:", error instanceof Error ? error.stack : String(error));
  process.exit(1);
});
